# Entity classes with inheritance and interface implementation
from core_types import Status, IIdentifiable

# Abstract base class for all entities
@abstract
class Entity:
    name: str
    status: Status

    def __init__(self, name: str):
        self.name = name
        self.status = Status.ACTIVE

    @abstract
    def display(self) -> str:
        ...

    @virtual
    def get_status_text(self) -> str:
        if self.status == Status.ACTIVE:
            return "active"
        elif self.status == Status.PENDING:
            return "pending"
        else:
            return "inactive"

# Concrete class implementing interface and inheriting
class Person(Entity, IIdentifiable):
    _id: int
    age: int

    def __init__(self, name: str, id_val: int, age: int):
        super().__init__(name)
        self._id = id_val
        self.age = age

    # Implement interface method
    @override
    def get_id(self) -> int:
        return self._id

    @override
    def display(self) -> str:
        return f"Person: {self.name}"

    @override
    def get_status_text(self) -> str:
        base: str = super().get_status_text()
        return f"person is {base}"

    def describe(self) -> str:
        return f"Person #{self.get_id()}: {self.name}"

# Another concrete class
class Task(Entity, IIdentifiable):
    _id: int
    priority_val: int

    def __init__(self, name: str, id_val: int, priority: int):
        super().__init__(name)
        self._id = id_val
        self.priority_val = priority
        self.status = Status.PENDING

    # Implement interface method
    @override
    def get_id(self) -> int:
        return self._id

    def describe(self) -> str:
        return f"Task #{self.get_id()}: {self.name}"

    @override
    def display(self) -> str:
        return f"Task: {self.name} (priority {self.priority_val})"
